const raw = $input.first().json;
const body = raw.body || raw;

const norm = value => String(value || '').trim().toLowerCase();
let role = norm(body.role || '');
if (role === 'admin') role = 'mentor';

const taskId = String(body.taskId || body.Task_ID || '').trim();
const email = norm(body.email || body.coachEmail || '');
const sessionToken = String(body.sessionToken || body.session_token || '').trim();
const lichessId = String(body.lichessId || body.Lichess_ID || '').trim();
const month = String(body.month || '').trim();

if (!sessionToken) throw new Error('Missing session token. Please login again.');
if (!email) throw new Error('Email is required.');
if (!taskId && !lichessId) throw new Error('Open a task or enter a Lichess ID first.');

return [{ json: { taskId, email, role, sessionToken, lichessId, month } }];

const request = $items('Normalize Lichess Request')[0].json;
const sessions = (() => { try { return $items('Read OTP Store').map(i => i.json); } catch (e) { return []; } })();
const tasks = $input.all().map(i => i.json);

const norm = value => String(value || '').trim().toLowerCase();
const get = (row, keys, fallback='') => {
  for (const k of keys) {
    if (row && row[k] !== undefined && row[k] !== null && String(row[k]).trim() !== '') return row[k];
  }
  return fallback;
};

function validSession() {
  const token = String(request.sessionToken || '').trim();
  const requestEmail = norm(request.email || '');
  let requestRole = norm(request.role || '');
  if (requestRole === 'admin') requestRole = 'mentor';

  if (!token) throw new Error('Missing session token. Please login again.');

  const usedSessions = sessions
    .filter(row => ['true','yes','1'].includes(norm(row.Used || row.used)))
    .sort((a,b) => new Date(b.UsedAt || b.CreatedAt || 0).getTime() - new Date(a.UsedAt || a.CreatedAt || 0).getTime());

  const match = usedSessions.find(row => String(row.SessionToken || row.sessionToken || '').trim() === token);

  if (match) {
    const usedAt = new Date(match.UsedAt || match.CreatedAt || '').getTime();
    if (!usedAt || Number.isNaN(usedAt)) throw new Error('Session timestamp missing. Please login again.');
    if (Date.now() > usedAt + 12 * 60 * 60 * 1000) throw new Error('Session expired. Please login again.');
    return { email: norm(match.Email || match.email), role: norm(match.Role || match.role), sessionToken: token };
  }

  // Same practical fallback used in the read/write workflows.
  if (sessions.length === 0 && token.startsWith('sess_n8n_') && requestEmail) {
    return { email: requestEmail, role: requestRole || (requestEmail === 'contact@envisionchessacademy.com' ? 'mentor' : 'coach'), sessionToken: token };
  }

  throw new Error(`Invalid or expired session. Please login again. Debug: sessionsRead=${sessions.length}`);
}

function monthBounds(monthValue) {
  const raw = String(monthValue || '').trim();
  let d = raw ? new Date(raw) : new Date();
  if (Number.isNaN(d.getTime())) {
    const m = raw.match(/^(\d{4})-(\d{2})/);
    if (m) d = new Date(`${m[1]}-${m[2]}-01T00:00:00.000Z`);
  }
  if (Number.isNaN(d.getTime())) d = new Date();
  const start = new Date(d.getFullYear(), d.getMonth(), 1, 0, 0, 0, 0);
  const end = new Date(d.getFullYear(), d.getMonth() + 1, 1, 0, 0, 0, 0);
  return { since: start.getTime(), until: end.getTime(), monthLabel: start.toLocaleString('en-IN', {month:'short', year:'numeric'}) };
}

const session = validSession();
const taskId = String(request.taskId || '').trim();
const task = taskId ? tasks.find(row => String(get(row, ['Task_ID','TaskId','taskId'])).trim() === taskId) : null;

if (taskId && !task) throw new Error('Task not found for Lichess fetch.');

if (task && session.role === 'coach') {
  const coachEmail = norm(get(task, ['Coach_Email','coachEmail']));
  if (coachEmail && coachEmail !== session.email) throw new Error('This task is not assigned to this coach.');
}

let lichessId = String(request.lichessId || '').trim();
if (!lichessId && task) lichessId = String(get(task, ['Lichess_ID','Lichess Id','lichessId'])).trim();
if (!lichessId) throw new Error('No Lichess ID found for this task.');

const bounds = monthBounds(request.month || get(task || {}, ['Month','month']) || '');

return [{ json: {
  ...request,
  sessionEmail: session.email,
  sessionRole: session.role,
  taskId,
  studentName: task ? get(task, ['Student_Name','studentName']) : '',
  lichessId,
  since: bounds.since,
  until: bounds.until,
  monthLabel: bounds.monthLabel
} }];

const request = $input.first().json;
const username = String(request.lichessId || '').trim();
const encoded = encodeURIComponent(username);

if (!username) throw new Error('Lichess ID missing.');

async function fetchText(url, headers = {}) {
  const res = await fetch(url, { headers });
  const text = await res.text();
  if (!res.ok) {
    if (res.status === 404) throw new Error(`Lichess user not found: ${username}`);
    throw new Error(`Lichess request failed (${res.status}): ${text.slice(0, 300)}`);
  }
  return text;
}

async function fetchJson(url) {
  const text = await fetchText(url, { 'Accept': 'application/json' });
  try { return JSON.parse(text); } catch (e) { throw new Error('Lichess profile did not return valid JSON.'); }
}

const profile = await fetchJson(`https://lichess.org/api/user/${encoded}`);

const gamesUrl = new URL(`https://lichess.org/api/games/user/${encoded}`);
gamesUrl.searchParams.set('since', String(request.since));
gamesUrl.searchParams.set('until', String(request.until));
gamesUrl.searchParams.set('max', '200');
gamesUrl.searchParams.set('rated', 'true');
gamesUrl.searchParams.set('sort', 'dateDesc');
gamesUrl.searchParams.set('opening', 'false');
gamesUrl.searchParams.set('moves', 'false');
gamesUrl.searchParams.set('pgnInJson', 'false');
gamesUrl.searchParams.set('tags', 'false');
gamesUrl.searchParams.set('clocks', 'false');
gamesUrl.searchParams.set('evals', 'false');
gamesUrl.searchParams.set('accuracy', 'false');

const gamesText = await fetchText(gamesUrl.toString(), { 'Accept': 'application/x-ndjson' });
const games = gamesText.trim()
  ? gamesText.trim().split(/\n+/).map(line => {
      try { return JSON.parse(line); } catch (e) { return null; }
    }).filter(Boolean)
  : [];

const userLower = username.toLowerCase();
let wins = 0, draws = 0, losses = 0, ratingDiffTotal = 0, ratingDiffCount = 0;
let bestWin = null;
let latestRatingFromGames = null;
let firstRatingFromGames = null;
const perfCounts = {};

for (const game of games) {
  const whiteName = String(game.players?.white?.user?.name || game.players?.white?.user?.id || '').toLowerCase();
  const blackName = String(game.players?.black?.user?.name || game.players?.black?.user?.id || '').toLowerCase();
  const color = whiteName === userLower ? 'white' : (blackName === userLower ? 'black' : '');
  if (!color) continue;
  const opponentColor = color === 'white' ? 'black' : 'white';
  const player = game.players?.[color] || {};
  const opponent = game.players?.[opponentColor] || {};
  const perf = game.perf || 'standard';
  perfCounts[perf] = (perfCounts[perf] || 0) + 1;

  if (player.rating && latestRatingFromGames === null) latestRatingFromGames = player.rating;
  if (player.rating) firstRatingFromGames = player.rating;

  if (typeof player.ratingDiff === 'number') {
    ratingDiffTotal += player.ratingDiff;
    ratingDiffCount += 1;
  }

  if (!game.winner) {
    draws += 1;
  } else if (game.winner === color) {
    wins += 1;
    const opponentRating = Number(opponent.rating || 0);
    if (!bestWin || opponentRating > bestWin.opponentRating) {
      const opponentName = opponent.user?.name || opponent.user?.id || 'opponent';
      bestWin = { opponentName, opponentRating, perf, date: game.createdAt };
    }
  } else {
    losses += 1;
  }
}

const gamesPlayed = wins + draws + losses;
const preferredPerf = Object.keys(perfCounts).sort((a,b) => perfCounts[b] - perfCounts[a])[0] || 'rapid';
const perfs = profile.perfs || {};
const standardPerf = perfs[preferredPerf] || perfs.rapid || perfs.blitz || perfs.classical || perfs.bullet || {};
const puzzlePerf = perfs.puzzle || {};
const currentRating = standardPerf.rating || latestRatingFromGames || 'Unrated';
let ratingChange = 'N/A';
if (ratingDiffCount) {
  ratingChange = ratingDiffTotal > 0 ? `+${ratingDiffTotal}` : String(ratingDiffTotal);
} else if (latestRatingFromGames !== null && firstRatingFromGames !== null) {
  const diff = latestRatingFromGames - firstRatingFromGames;
  ratingChange = diff > 0 ? `+${diff}` : String(diff);
}

const puzzleActivity = puzzlePerf.rating
  ? `Puzzle rating ${puzzlePerf.rating}${puzzlePerf.games ? ` · ${puzzlePerf.games} puzzles` : ''}`
  : 'N/A';

const bestResult = bestWin
  ? `Win vs ${bestWin.opponentName}${bestWin.opponentRating ? ` (${bestWin.opponentRating})` : ''}`
  : (gamesPlayed ? 'No win found this month' : 'No rated games this month');

return [{ json: {
  ok: true,
  data: {
    lichessId: username,
    source: 'lichess',
    month: request.monthLabel,
    studentRating: String(currentRating),
    gamesPlayed: String(gamesPlayed),
    wins: String(wins),
    draws: String(draws),
    losses: String(losses),
    ratingChange,
    puzzleActivity,
    bestResult,
    perfType: preferredPerf,
    message: `Lichess snapshot fetched for ${username}: ${gamesPlayed} rated games in ${request.monthLabel}.`
  }
} }];
